package ru.memearena.security;
import org.springframework.context.annotation.*; import org.springframework.security.config.annotation.web.builders.HttpSecurity; import org.springframework.security.config.http.SessionCreationPolicy; import org.springframework.security.web.*; import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
@Configuration public class SecurityConfig { @Bean SecurityFilterChain chain(HttpSecurity http,BearerTokenAuthenticationFilter bearer,RestAuthenticationEntryPoint entry) throws Exception { return http.csrf(c->c.disable()).sessionManagement(s->s.sessionCreationPolicy(SessionCreationPolicy.STATELESS)).exceptionHandling(e->e.authenticationEntryPoint(entry)).authorizeHttpRequests(a->a.requestMatchers("/api/v1/users/guest","/api/v1/health","/api/v1/memes/top","/api/v1/media/*/content","/actuator/health","/v3/api-docs/**","/swagger-ui/**").permitAll().requestMatchers("/api/v1/admin/**").hasRole("ADMIN").anyRequest().authenticated()).addFilterBefore(bearer, UsernamePasswordAuthenticationFilter.class).build(); } }
